INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('10-personal-brand',2,10,'PERSONAL BRAND','Xay dung nhan hinh ca nhan',10,'draft','2026-06-20T11:07:43Z','2026-06-20T11:07:43Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('17d0df59-7ba7-4440-b615-b53fdb34cb74','10-personal-brand',NULL,2,'10.1 Personal Brand là gì?','101-personal-brand-la-gi',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b9d0c4d8-301d-485b-a7e3-0e781f9c434f','17d0df59-7ba7-4440-b615-b53fdb34cb74',0,'image',NULL,'book/10-personal-brand/139394f8-1ab5-4099-bcd5-fdde49a2565a-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('49341958-bd6a-4c35-a3df-70d899016179','17d0df59-7ba7-4440-b615-b53fdb34cb74',1,'text','Personal Brand không chỉ là “thương hiệu cá nhân” theo nghĩa phổ thông. Trong bối cảnh nha khoa, đó là tổng hòa giữa chuyên môn, cách xuất hiện, cách giao tiếp, quan điểm điều trị và những bằng chứng đủ mạnh để người khác tin vào một bác sĩ hoặc founder.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3717c9d3-8448-4d03-a696-05912416f044','17d0df59-7ba7-4440-b615-b53fdb34cb74',2,'text','Nói cách khác, Personal Brand là hình ảnh mà thị trường nhớ đến khi nhắc về một con người. Hình ảnh ấy không được tạo ra từ lời nói suông, mà đến từ sự nhất quán giữa điều người đó biết, điều họ làm và điều bệnh nhân trải nghiệm thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9b4a204-7280-4bea-8820-8e473760927f','17d0df59-7ba7-4440-b615-b53fdb34cb74',3,'text','Với một phòng khám nha khoa, Personal Brand là điểm chạm đầu tiên của niềm tin. Khi bệnh nhân chưa hiểu hết về kỹ thuật, chưa phân biệt được các phương án điều trị, họ thường chọn người mà họ cảm thấy đáng tin nhất để bắt đầu hành trình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f7bc68f9-0adc-4129-bda7-75e20e20095a','17d0df59-7ba7-4440-b615-b53fdb34cb74',4,'text','Key insight',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e47e948-ab01-4ac5-b6cb-f596550e385d','17d0df59-7ba7-4440-b615-b53fdb34cb74',5,'text','*Personal Brand không phải là phần trang trí của marketing. Nó là trụ cột tạo niềm tin đầu tiên trong Dental Empire, và là điểm khởi đầu của toàn bộ vòng lặp tăng trưởng.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1ff7b122-6655-47d4-847d-549b011537dd','10-personal-brand',NULL,2,'10.2 Vai trò của Personal Brand trong Dental Empire  Flywheel','102-vai-tro-cua-personal-brand-trong-dental-empire-flywheel',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f0cb4a4c-dc8b-4c62-9fa1-5008e9da7926','1ff7b122-6655-47d4-847d-549b011537dd',6,'text','Personal Brand trong Dental Empire là **gương mặt đại diện cho niềm tin**. Nó không được xây để “nổi tiếng”, mà để biến chuyên môn của bác sĩ/founder thành một dạng uy tín có thể nhìn thấy, nghe thấy và kiểm chứng được.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6f03fd6e-be8b-46f6-bcf5-538386965ecf','1ff7b122-6655-47d4-847d-549b011537dd',7,'text','Trong thực tế, chuỗi này là đường đi từ “người lạ” đến “bệnh nhân” và cuối cùng là “người giới thiệu”. Nếu một mắt xích yếu, toàn bộ hệ thống tăng trưởng sẽ giảm hiệu quả, dù phòng khám có nhiều quảng cáo hay nhiều kênh truyền thông.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d4f9bf8e-ee23-4b38-92c6-3934e23f800e','10-personal-brand','1ff7b122-6655-47d4-847d-549b011537dd',3,'Vì sao nó quan trọng','vi-sao-no-quan-trong',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3f0b84b8-27fa-4530-bc51-36762eeac336','d4f9bf8e-ee23-4b38-92c6-3934e23f800e',8,'text','Trong nha khoa, bệnh nhân không chỉ chọn một phòng khám; họ chọn một **con người** mà họ tin. Vì vậy, Personal Brand không phải phần phụ của marketing, mà là trụ cột đầu tiên tạo niềm tin trước khi bệnh nhân quyết định đặt lịch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4baafb51-79fc-4d51-90a4-4cb80e552a0a','d4f9bf8e-ee23-4b38-92c6-3934e23f800e',9,'text','Khi bác sĩ/founder xuất hiện với kiến thức rõ ràng, quan điểm điều trị nhất quán và bằng chứng thật, bệnh nhân sẽ tin nhanh hơn, hỏi ít nghi ngờ hơn và dễ ra quyết định hơn. Điều này đặc biệt quan trọng với các dịch vụ giá trị cao như implant, niềng răng, veneer hay phục hình, nơi cảm giác an tâm thường quan trọng không kém bản thân kỹ thuật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('84b9e385-2212-4e72-8291-48efb2cc7653','10-personal-brand','1ff7b122-6655-47d4-847d-549b011537dd',3,'Vai trò trong hệ thống','vai-tro-trong-he-thong',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d5a81471-bbad-471d-8975-241e17295f44','84b9e385-2212-4e72-8291-48efb2cc7653',10,'text','Personal Brand không đứng một mình; nó nuôi toàn bộ hệ sinh thái Dental Empire. Nó tạo đầu vào cho Media Network bằng nội dung chuyên môn, case thật, góc nhìn điều trị và câu chuyện bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56dff175-cf98-4641-9a74-5b9fad3bb241','84b9e385-2212-4e72-8291-48efb2cc7653',11,'text','Từ đó, Media Network khuếch đại sự hiện diện của bác sĩ trên TikTok, Facebook, YouTube, Google và website, còn Clinic System bảo đảm lời hứa truyền thông được thực hiện bằng trải nghiệm thật trong phòng khám. Khi ba phần này khớp nhau, niềm tin không chỉ được tạo ra mà còn được tích lũy thành review và referral.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d97dbf98-6b77-4008-8db8-a8a9a8452c56','10-personal-brand','1ff7b122-6655-47d4-847d-549b011537dd',3,'Mục tiêu cốt lõi','muc-tieu-cot-loi',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cc1d3b40-36fb-4802-8895-50ae8c8bc7fa','d97dbf98-6b77-4008-8db8-a8a9a8452c56',12,'text','Mục tiêu chính của Personal Brand là: **biến chuyên môn của bác sĩ thành niềm tin có thể kiểm chứng**. Điều đó có nghĩa là bệnh nhân không chỉ “thấy bác sĩ hay”, mà còn thấy được bác sĩ hiểu vấn đề, có quy trình, có case thật và có tiêu chuẩn điều trị rõ ràng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('14324978-aecb-40e8-adfc-6224f1a875a0','d97dbf98-6b77-4008-8db8-a8a9a8452c56',13,'text','Một Personal Brand mạnh sẽ giúp phòng khám:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('26d51ac3-1fcc-4fe2-8acd-29fc785d8cfb','d97dbf98-6b77-4008-8db8-a8a9a8452c56',14,'text','- Tăng độ tin cậy trước khi bệnh nhân đến khám.- Giảm phụ thuộc vào quảng cáo giá rẻ.- Tăng tỷ lệ chuyển đổi từ người xem thành người đặt lịch.- Tạo lợi thế cạnh tranh dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8cddb706-bbce-423f-90f0-c3baeeb12b6c','10-personal-brand','1ff7b122-6655-47d4-847d-549b011537dd',3,'Bức tranh liên hệ','buc-tranh-lien-he',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('53cc3485-cd7c-4bb6-a0ad-66c97751e23d','8cddb706-bbce-423f-90f0-c3baeeb12b6c',15,'image',NULL,'book/10-personal-brand/b7c02d0b-269f-4e64-8cb8-118a2adc1492-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15dd64d0-c7bb-4b7c-80f7-3e0045bb84d1','8cddb706-bbce-423f-90f0-c3baeeb12b6c',16,'text','`Personal Brand = niềm tin cá nhân`
`Media Network = độ phủ`
`Clinic System = trải nghiệm thật`
`Growth Engine = chuyển đổi`
`Trust Assets = bằng chứng`
`Referral = tăng trưởng lặp lại`',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('74f1b8b6-8190-4300-9d40-4f8b79d20f63','10-personal-brand','1ff7b122-6655-47d4-847d-549b011537dd',3,'Vai trò của bác sĩ / founder trong việc tạo niềm tin','vai-tro-cua-bac-si-founder-trong-viec-tao-niem-tin',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2b5ff5cd-968f-48ea-ba02-79cfc0e0c96d','74f1b8b6-8190-4300-9d40-4f8b79d20f63',17,'image',NULL,'book/10-personal-brand/3ed313c7-64de-4a4a-9fe6-d1e839ab1e82-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7c1a72c6-7d5c-4543-94d3-3a942c2261e1','74f1b8b6-8190-4300-9d40-4f8b79d20f63',18,'text','Trong mô hình Dental Empire, bác sĩ hoặc founder không chỉ là người điều trị. Họ còn là người đại diện cho tiêu chuẩn chuyên môn, cho cách làm nghề và cho lời hứa mà phòng khám đưa ra với bệnh nhân. Vì vậy, niềm tin không chỉ nằm ở tên phòng khám, mà còn nằm ở con người đứng sau nó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7fe24c1-2a7d-4ffc-b512-beac3d9c2c53','74f1b8b6-8190-4300-9d40-4f8b79d20f63',19,'text','Khi bác sĩ/founder xuất hiện đều đặn với góc nhìn rõ ràng, cách giải thích dễ hiểu và bằng chứng thật, bệnh nhân sẽ cảm thấy yên tâm hơn trước khi quyết định đặt lịch. Đặc biệt trong các dịch vụ có giá trị cao hoặc liên quan đến rủi ro cảm nhận như implant, niềng răng hay phục hình, vai trò của bác sĩ trong việc “giảm lo lắng” quan trọng không kém vai trò chuyên môn thuần túy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7b1854f2-5f7c-449c-bf83-53f4ee330376','74f1b8b6-8190-4300-9d40-4f8b79d20f63',20,'text','Có thể hiểu đơn giản: phòng khám bán dịch vụ, nhưng bệnh nhân mua sự an tâm. Và người tạo ra sự an tâm ban đầu thường chính là **bác sĩ hoặc founder.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('88b4e003-da81-47e9-ba5a-d9794f066e06','74f1b8b6-8190-4300-9d40-4f8b79d20f63',21,'text','Vì vậy, thương hiệu cá nhân của bác sĩ hoặc founder là tài sản chiến lược giúp phòng khám:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c61e4838-bf40-4cb2-9169-30b406c7b7b4','74f1b8b6-8190-4300-9d40-4f8b79d20f63',22,'text','- Tăng độ tin cậy trước khi bệnh nhân đến khám- Giảm phụ thuộc vào quảng cáo giá rẻ- Tăng tỷ lệ chuyển đổi từ người xem thành người đặt lịch- Tạo lợi thế cạnh tranh dài hạn- Xây dựng uy tín chuyên môn trên mạng xã hội, Google và AI Search',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dbb7d42f-307c-424d-b69c-3083489f3b05','10-personal-brand','1ff7b122-6655-47d4-847d-549b011537dd',3,'Chuyên môn, thái độ và độ hiện diện','chuyen-mon-thai-o-va-o-hien-dien',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('60ee7ae5-b66c-4509-a45a-a38939915c35','dbb7d42f-307c-424d-b69c-3083489f3b05',23,'image',NULL,'book/10-personal-brand/05e094a2-42e4-4ab0-8d59-0ee46651e500-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('61a9ddd6-3f8f-4a1c-bcd8-a409e1c76333','dbb7d42f-307c-424d-b69c-3083489f3b05',24,'text','Một Personal Brand mạnh không thể chỉ dựa vào một yếu tố đơn lẻ. Nó cần ba lớp kết hợp chặt chẽ:** chuyên môn, thái độ và độ hiện diện.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5cc15282-a4c4-49fd-83a2-4147396337cc','dbb7d42f-307c-424d-b69c-3083489f3b05',25,'text','Chuyên môn giúp người khác tin rằng bạn thực sự hiểu vấn đề và có khả năng xử lý vấn đề đó. Thái độ giúp họ cảm nhận được sự cẩn trọng, tử tế và trách nhiệm. Độ hiện diện giúp những giá trị đó được nhìn thấy lặp đi lặp lại trên nhiều kênh, thay vì chỉ tồn tại trong một lần gặp mặt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('821d3742-9b91-4096-9815-e24a24e22618','dbb7d42f-307c-424d-b69c-3083489f3b05',26,'text','Nếu thiếu chuyên môn, thương hiệu cá nhân sẽ mỏng. Nếu thiếu thái độ, thương hiệu sẽ lạnh. Nếu thiếu hiện diện, thương hiệu sẽ không đủ lâu để đi vào trí nhớ thị trường. Bởi vậy, Personal Brand không phải là một bức ảnh đẹp hay một vài video viral, mà là một hệ thống thể hiện con người đó một cách nhất quán và đáng tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b7b88ae6-d5a5-41a3-8ee3-6a7f44635462','10-personal-brand','1ff7b122-6655-47d4-847d-549b011537dd',3,'Personal Brand nuôi Media Network như thế nào?','personal-brand-nuoi-media-network-nhu-the-nao',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6511f9e7-6cfc-4980-8eb1-8756587d21d7','b7b88ae6-d5a5-41a3-8ee3-6a7f44635462',27,'image',NULL,'book/10-personal-brand/193d4a59-999a-4788-bfcb-92120f882516-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('34aa3853-7390-4e35-9a50-bacabc9fbea3','b7b88ae6-d5a5-41a3-8ee3-6a7f44635462',28,'text','Personal Brand là nguồn đầu vào của Media Network. Khi một bác sĩ/founder có góc nhìn chuyên môn rõ ràng, một phong cách diễn đạt riêng và nhiều chất liệu thực tế từ điều trị, toàn bộ nội dung truyền thông sẽ có “linh hồn” riêng thay vì chỉ là các bài đăng rời rạc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fd913ba5-5fd6-47e0-9371-8bf51c799bcc','b7b88ae6-d5a5-41a3-8ee3-6a7f44635462',29,'text','Từ một góc nhìn chuyên môn, có thể tạo ra video ngắn, bài viết Facebook, nội dung Zalo, bài SEO, livestream hỏi đáp hoặc case study. Mỗi định dạng khác nhau lại giúp cùng một thông điệp tiếp cận thêm một nhóm bệnh nhân khác nhau. Vì vậy, Personal Brand không đứng ngoài Media Network; nó chính là nhân vật trung tâm để Media Network vận hành hiệu quả.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c9a63c3c-3c48-40c7-818e-863799b1cbe5','b7b88ae6-d5a5-41a3-8ee3-6a7f44635462',30,'text','Khi Personal Brand đủ mạnh, nội dung sẽ không còn mang cảm giác “quảng cáo phòng khám”. Thay vào đó, nó trở thành chuỗi tín hiệu chuyên môn giúp thị trường dần hình thành niềm tin, rồi từ niềm tin đó mới chuyển sang quan tâm, inbox và đặt lịch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('857f3daf-a653-4b19-a790-42bad6d47f15','10-personal-brand','1ff7b122-6655-47d4-847d-549b011537dd',3,'Sai lầm thường gặp khi xây Personal Brand','sai-lam-thuong-gap-khi-xay-personal-brand',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a5bf84dc-c837-455b-b115-6d784f26393e','857f3daf-a653-4b19-a790-42bad6d47f15',31,'text','Sai lầm phổ biến nhất là xây Personal Brand quá chung chung. Khi bác sĩ/founder cố gắng nói về mọi thứ, thị trường sẽ không nhớ rõ họ mạnh ở đâu và khác biệt ở điểm nào. Một thương hiệu cá nhân hiệu quả phải có định vị, chứ không phải chỉ có sự xuất hiện.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bb327e91-c6d8-4cce-b055-d9b85a023f6c','857f3daf-a653-4b19-a790-42bad6d47f15',32,'image',NULL,'book/10-personal-brand/25521c33-f8d6-488d-af17-55a16d32107b-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6906d59a-0a37-4c1c-9c9b-9e10d88194a5','857f3daf-a653-4b19-a790-42bad6d47f15',33,'text','Sai lầm thứ hai là chạy theo viral hoặc xây hình ảnh quá phô trương. Trong ngành nha khoa, điều này dễ làm giảm cảm giác chuyên nghiệp và có thể khiến người xem nghi ngờ về mức độ nghiêm túc của chuyên môn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10ef6a17-20d0-4a88-bd6e-3b99707b23fc','857f3daf-a653-4b19-a790-42bad6d47f15',34,'text','Sai lầm thứ ba là nói hay trên nội dung nhưng trải nghiệm thực tế của bệnh nhân lại không tương xứng, khiến niềm tin bị đứt gãy rất nhanh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ab83b24a-9e0e-4e68-aa02-597c98e60942','857f3daf-a653-4b19-a790-42bad6d47f15',35,'text','Một lỗi khác cũng rất thường gặp là thiếu nhất quán. Nếu hôm nay nói về điều trị rất chuẩn mực, ngày mai lại dùng thông điệp quá giật gân, hoặc hình ảnh cá nhân không đồng bộ với giá trị chuyên môn, Personal Brand sẽ bị loãng và khó tích lũy về dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b2cdc772-6357-40a1-947c-6aaace5210ab','10-personal-brand',NULL,2,'10.3 Cách xây dựng Personal Brand','103-cach-xay-dung-personal-brand',10,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('28bb3ee2-d8fb-4bdf-9a60-39405baffa6c','10-personal-brand','b2cdc772-6357-40a1-947c-6aaace5210ab',3,'Rào cản khiến nhiều người không dám xây dựng Personal Branding','rao-can-khien-nhieu-nguoi-khong-dam-xay-dung-personal-branding',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('72014b28-e7f3-45bf-b462-5a139e668f94','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',36,'image',NULL,'book/10-personal-brand/0f691f0e-b5a4-4058-9dc8-02f9000d6610-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b2903102-f1c6-4e1f-971b-1755e9f44c25','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',37,'text','Tôi gặp không ít người muốn xây personal brand, nhưng cứ đứng ở vạch xuất phát rất lâu. Họ không thiếu ý tưởng, cũng không thiếu điều để nói, mà thường vướng vào một cảm giác rất quen: **sợ**. Sợ bị nhìn thấy, sợ bị đánh giá, sợ nói sai, sợ mình chưa đủ giỏi để xuất hiện trước người khác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6af06acc-1c64-4094-ad76-98ed715897dc','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',38,'text','Thực ra, đây là điều rất tự nhiên. Khi một người bắt đầu có mặt nhiều hơn trên mạng xã hội, họ cũng đồng nghĩa bước vào một không gian mà ở đó ai cũng có thể quan sát, bình luận, so sánh. Với những người làm chuyên môn, áp lực này còn lớn hơn, vì personal brand không chỉ là chuyện hình ảnh; nó còn gắn với uy tín, trách nhiệm và niềm tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('602dd59a-dfc0-4afe-b97b-0cca57aa3617','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',39,'text','**Những nỗi sợ thường gặp**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a0ea18fb-f780-4223-8081-ead96acb9907','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',40,'text','Có người sợ mình trông như đang khoe khoang nên chọn cách im lặng. Có người sợ bị phản biện nên chỉ nói những điều an toàn, chung chung. Có người lại sợ mình chưa đủ kinh nghiệm, chưa đủ thành tựu, chưa đủ “hay” để bắt đầu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0c083c91-2904-459c-846b-db2bf4092e1d','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',41,'text','Cũng có người không dám đi xa hơn vì nghĩ personal branding phải thật chỉn chu ngay từ đầu. Họ chờ đến khi mọi thứ hoàn hảo mới dám xuất hiện. Nhưng sự thật là, thương hiệu cá nhân không được sinh ra từ sự hoàn hảo. Nó lớn lên từ sự nhất quán, từ những lần xuất hiện đều đặn, và từ những bằng chứng nhỏ nhưng thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48c4dc00-239f-41d0-9f00-72749e1029bc','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',42,'text','**Điều khiến việc bắt đầu trở nên khó hơn**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('faed4df6-4607-4418-b462-b063c5edf406','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',43,'text','Trong nhiều trường hợp, rào cản không nằm ở kỹ năng mà nằm ở cách nhìn. Khi một người nghĩ personal brand là “tự quảng cáo bản thân”, họ sẽ cảm thấy ngại. Nhưng khi hiểu rằng personal brand là cách để chuyên môn được nhìn thấy rõ hơn, được hiểu đúng hơn và được tin hơn, tâm thế sẽ khác đi rất nhiều.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('539e3047-4d82-4c5a-9c28-707174a672dd','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',44,'text','Với bác sĩ hay founder, điều này càng rõ. Nếu bên trong chưa có hệ thống nội dung, chưa có case thật, chưa có review, chưa có trải nghiệm đủ tốt, họ sẽ dễ thấy mình “chưa có gì để nói”. Nhưng chính vì vậy mà personal brand không nên bị hiểu như một lớp trang điểm bên ngoài. Nó là một hệ thống tích lũy niềm tin theo thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c225c2c-f493-42ae-8a89-244f4b95e2bd','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',45,'text','**Cách vượt qua rào cản này**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ebf817c4-ba42-427e-bd08-43c26b975880','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',46,'text','Cách tốt nhất không phải là cố gắng làm thật lớn ngay từ đầu, mà là bắt đầu thật nhỏ nhưng thật rõ. Chỉ cần một góc chuyên môn, một vài câu hỏi bệnh nhân hay gặp, một case thật, một quan điểm điều trị rõ ràng, bạn đã có thể bắt đầu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a1bf0c3-5f76-4f98-af52-e45f41c44c6b','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',47,'text','Điều quan trọng hơn cả là sự thật. Người xem không cần bạn hoàn hảo. Họ cần bạn rõ ràng, nhất quán và đáng tin. Một thương hiệu cá nhân tốt không phải là thứ khiến người khác trầm trồ ngay lập tức, mà là thứ khiến họ dần thấy yên tâm mỗi lần gặp lại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0fa3b1fe-61a2-440c-adcf-7ef6ac09a95c','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',48,'text','**Một cách hiểu đơn giản**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1531de6e-70b7-472c-98b7-5efdea5be9d1','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',49,'text','Personal brand giống như việc thắp đèn trong một căn phòng. Bạn không cần thắp sáng cả ngôi nhà ngay từ đêm đầu tiên. Bạn chỉ cần bắt đầu bằng một ngọn đèn nhỏ, đủ để người khác nhìn thấy bạn đang ở đâu, làm gì, và vì sao họ có thể tin bạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('72f05277-3bbf-4090-876c-6269b878db67','28bb3ee2-d8fb-4bdf-9a60-39405baffa6c',50,'text','Khi ánh sáng đó được giữ đều, nó không còn là một lần xuất hiện nữa. Nó trở thành dấu hiệu nhận biết. Và từ dấu hiệu nhận biết, niềm tin mới bắt đầu hình thành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('90ec0477-fe58-4fc8-b873-607eec8eb012','10-personal-brand','b2cdc772-6357-40a1-947c-6aaace5210ab',3,'Thành phần cốt lõi của Personal Brand','thanh-phan-cot-loi-cua-personal-brand',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b2e41dfb-bbaf-4e42-b4ba-6b49f5ec3576','90ec0477-fe58-4fc8-b873-607eec8eb012',51,'image',NULL,'book/10-personal-brand/964058a5-6c20-4330-9d98-5fd8642f9b11-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c9c3a406-e2c4-42db-8a16-b6538fd4004c','10-personal-brand','b2cdc772-6357-40a1-947c-6aaace5210ab',3,'Định vị Personal Brand cho bác sĩ nha khoa','inh-vi-personal-brand-cho-bac-si-nha-khoa',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('76c311b3-a1cd-4343-b3ad-1f7e7e834263','c9c3a406-e2c4-42db-8a16-b6538fd4004c',52,'text','Một bác sĩ không nên bước ra thị trường với một hình ảnh quá rộng. Càng chung chung, càng khó được nhớ; càng rõ ràng, càng dễ được tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9f007dc7-7d06-4b22-aafa-3d35ab02f19e','c9c3a406-e2c4-42db-8a16-b6538fd4004c',53,'text','Định vị Personal Brand là cách bác sĩ trả lời thật gọn mà thật sâu năm câu hỏi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1ef9d225-f52e-4b90-a43a-4a64c8b3c592','c9c3a406-e2c4-42db-8a16-b6538fd4004c',54,'text','- **Tôi là ai? **- **Tôi giỏi nhất về vấn đề gì? **- **Tôi phục vụ nhóm bệnh nhân nào? **- **Tôi đại diện cho tiêu chuẩn điều trị nào? **- **Vì sao bệnh nhân nên tin tôi?**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('725fb3e1-3665-45dd-b0dc-32bb521d57ab','c9c3a406-e2c4-42db-8a16-b6538fd4004c',55,'text','Khi có câu trả lời rõ, thương hiệu cá nhân mới có chỗ đứng thật sự trong lòng bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('24207178-92cd-435e-8df2-68448e4d4c5b','10-personal-brand','b2cdc772-6357-40a1-947c-6aaace5210ab',3,'Khung nội dung chính','khung-noi-dung-chinh',14,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ffeb72e7-7002-4db4-a33d-b7c086f0207c','10-personal-brand','24207178-92cd-435e-8df2-68448e4d4c5b',4,'Vì sao phải định vị','vi-sao-phai-inh-vi',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('edd405a7-07b9-4cae-9aef-a0f2d5554818','ffeb72e7-7002-4db4-a33d-b7c086f0207c',56,'text','Trong nha khoa, bệnh nhân thường không đủ chuyên môn để tự đánh giá kỹ thuật. Họ sẽ chọn người khiến họ cảm thấy an tâm, dễ hiểu và đáng tin. Vì vậy, định vị không phải để làm bác sĩ trông nổi bật hơn, mà để làm giá trị chuyên môn trở nên dễ nhận ra hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('533f77a9-1ee8-4977-afd7-8c81ff187846','10-personal-brand','24207178-92cd-435e-8df2-68448e4d4c5b',4,'Một định vị tốt cần gì','mot-inh-vi-tot-can-gi',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85463add-f00a-4595-8d3b-aebd6b6f4019','533f77a9-1ee8-4977-afd7-8c81ff187846',57,'text','Một định vị tốt luôn có ba lớp: rõ chuyên môn, rõ nhóm bệnh nhân và rõ tiêu chuẩn điều trị. Nếu thiếu một trong ba lớp đó, hình ảnh cá nhân sẽ dễ bị loãng và khó tạo niềm tin dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3b930e55-36f6-49d8-926b-1e93f5011023','533f77a9-1ee8-4977-afd7-8c81ff187846',58,'text','**Cách trả lời 5 câu hỏi**
***Tôi là [vai trò/chuyên môn], giúp [nhóm bệnh nhân] giải quyết [vấn đề cụ thể] bằng [tiêu chuẩn/phương pháp].***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf6bd36f-5007-4862-9ab8-dffebdd88cb6','533f77a9-1ee8-4977-afd7-8c81ff187846',59,'text','Ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('753b5e7a-edf3-4443-b08f-ed97d0cc843f','533f77a9-1ee8-4977-afd7-8c81ff187846',60,'text','- Tôi là bác sĩ chuyên phục hồi răng mất lâu năm bằng implant.- Tôi giúp bệnh nhân niềng răng hiểu rõ kế hoạch điều trị trước khi bắt đầu.- Tôi đại diện cho tiêu chuẩn điều trị tử tế, minh bạch và bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('180f868e-3d89-4b7f-86b8-c7d1b249250b','10-personal-brand','24207178-92cd-435e-8df2-68448e4d4c5b',4,'Bệnh nhân thật sự tin vào điều gì','benh-nhan-that-su-tin-vao-ieu-gi',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7e1b9322-ee28-444c-a24b-0f581139288e','180f868e-3d89-4b7f-86b8-c7d1b249250b',61,'text','Bệnh nhân không chỉ tin vào lời nói. Họ tin vào case thật, quy trình minh bạch, review, hình ảnh nhất quán và cách bác sĩ xuất hiện đều đặn trên các kênh. Đó là lý do Personal Brand không thể tách rời Content và Trust Assets.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1334b101-c7f3-48eb-bf74-30844c931a3a','180f868e-3d89-4b7f-86b8-c7d1b249250b',62,'text','**Key insight**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2ac509a3-fb01-4310-9b11-d4e5b466e2f9','180f868e-3d89-4b7f-86b8-c7d1b249250b',63,'text','***Định vị không làm bạn nhỏ đi; nó làm bạn rõ hơn.**** Khi bác sĩ rõ mình là ai và mình đại diện cho điều gì, bệnh nhân sẽ dễ nhớ, dễ hiểu và dễ tin hơn.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('06dde6a4-67ac-4cee-8ddb-bad97c901187','10-personal-brand','24207178-92cd-435e-8df2-68448e4d4c5b',4,'Ví dụ thực tế','vi-du-thuc-te',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ab89bc20-0635-49c9-b8dd-994088511b8d','06dde6a4-67ac-4cee-8ddb-bad97c901187',64,'text','Một bác sĩ nói “tôi làm nha khoa tổng quát” thường để lại cảm giác khá mờ. Nhưng nếu bác sĩ nói “tôi chuyên phục hồi răng mất lâu năm bằng implant, với quy trình tư vấn minh bạch và tiêu chuẩn điều trị bền vững”, người nghe sẽ hiểu ngay bác sĩ đó mạnh ở đâu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d76db608-bf4b-406c-a34a-56416031fcc5','10-personal-brand','24207178-92cd-435e-8df2-68448e4d4c5b',4,'Checklist triển khai','checklist-trien-khai',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d6fc1628-8ef3-4f36-8946-3f7f4aadc930','d76db608-bf4b-406c-a34a-56416031fcc5',65,'text','- Viết một câu giới thiệu ngắn về chuyên môn của mình.- Chọn một lĩnh vực mũi nhọn thay vì ôm quá rộng.- Xác định rõ nhóm bệnh nhân bạn muốn phục vụ nhất.- Ghi ra tiêu chuẩn điều trị mà bạn đại diện.- Kiểm tra lại: người ngoài đọc xong có hiểu bạn khác gì không.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('690bbae7-7993-43d2-b27c-cec38091d9eb','d76db608-bf4b-406c-a34a-56416031fcc5',66,'text','**Một Personal Brand tốt không bắt đầu từ việc nói nhiều, mà bắt đầu từ việc định vị đúng.** Khi bác sĩ biết mình đứng ở đâu, thị trường sẽ biết phải nhớ mình bằng điều gì.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2e565b85-c6a1-420b-a46d-ff57c878a678','d76db608-bf4b-406c-a34a-56416031fcc5',67,'text','*Ví dụ định vị:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2c14bbda-abff-4f47-9652-94753e107aeb','d76db608-bf4b-406c-a34a-56416031fcc5',68,'image',NULL,'book/10-personal-brand/449da23a-b2f8-4208-a4a1-ff3af0bcaf5e-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6a6f855d-8038-4089-8a3c-569bdc434e7e','10-personal-brand','b2cdc772-6357-40a1-947c-6aaace5210ab',3,'Trục nội dung của Personal Brand','truc-noi-dung-cua-personal-brand',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f3e1086-3184-498f-a644-e7f6e9b6f77c','6a6f855d-8038-4089-8a3c-569bdc434e7e',69,'text','Personal Brand cần được xây bằng nội dung đều đặn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b50edb3e-401e-45fc-8e02-8bee5fbe4df0','10-personal-brand','6a6f855d-8038-4089-8a3c-569bdc434e7e',4,'Nội dung chuyên môn','noi-dung-chuyen-mon',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d69f6428-66b2-4234-a13e-1eeb5615a934','b50edb3e-401e-45fc-8e02-8bee5fbe4df0',70,'text','Mục tiêu: chứng minh bác sĩ có năng lực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d90aa91-56d3-4d61-a042-c156b7907a62','b50edb3e-401e-45fc-8e02-8bee5fbe4df0',71,'text','Ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3f0fb3be-2df9-4b62-87ad-6b5c2354a21b','b50edb3e-401e-45fc-8e02-8bee5fbe4df0',72,'text','- Vì sao mất răng lâu ngày làm tiêu xương?- Niềng răng có làm yếu răng không?- Khi nào nên bọc răng sứ, khi nào không nên?- Implant có đau không?- Tẩy trắng răng có hại men răng không?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('178f0a6d-173e-4a3e-8d5a-e0c33bc3bc80','b50edb3e-401e-45fc-8e02-8bee5fbe4df0',73,'text','Dạng nội dung này giúp bệnh nhân thấy bác sĩ **hiểu vấn đề và có khả năng giải thích rõ ràng**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c6780fba-a928-4d53-8308-51d36b8e4b31','10-personal-brand','6a6f855d-8038-4089-8a3c-569bdc434e7e',4,'Nội dung giải thích sai lầm phổ biến','noi-dung-giai-thich-sai-lam-pho-bien',22,'[]');
