INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b9cb6cce-a5a7-4966-8215-0f9cdaefe1ac','c6780fba-a928-4d53-8308-51d36b8e4b31',75,'text','*Ví dụ:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6979f6e1-d057-42d8-86e1-acf9e395bdf6','c6780fba-a928-4d53-8308-51d36b8e4b31',76,'text','- *5 sai lầm khi chọn phòng khám niềng răng*- *Vì sao không nên làm răng sứ chỉ vì thấy quảng cáo giá rẻ?*- *Sai lầm khi mất răng nhưng trì hoãn trồng implant*- *Vì sao đau răng không nên tự mua thuốc uống lâu dài?*- *Vì sao review tốt chưa đủ, cần xem cả quy trình điều trị?*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e93c3980-35aa-4233-ad1c-30da5e6f8c3e','c6780fba-a928-4d53-8308-51d36b8e4b31',77,'text','Dạng nội dung này giúp bác sĩ trở thành **người bảo vệ lợi ích bệnh nhân**.',NULL,NULL,NULL,NULL,NULL);
