INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0f6c6a25-380c-4d66-a249-523fcc583157','4e84964c-f5fb-49a1-962b-1e074ac90b49',79,'text','*Ví dụ:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6ba87bfd-242b-490a-bf5c-c24e9c981371','4e84964c-f5fb-49a1-962b-1e074ac90b49',80,'text','- *Trước và sau khi niềng răng*- *Một ca mất răng lâu năm phục hồi bằng implant*- *Case răng xỉn màu cải thiện bằng veneer*- *Case sai khớp cắn được điều chỉnh từng bước*- *Case bệnh nhân từng sợ nha khoa nhưng đã điều trị thành công*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('14f01a1e-eb1a-4a1b-b02c-29402d2ef49f','4e84964c-f5fb-49a1-962b-1e074ac90b49',81,'text','Case thật là tài sản rất mạnh vì bệnh nhân tin vào **kết quả cụ thể hơn lời quảng cáo**.',NULL,NULL,NULL,NULL,NULL);
