INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6107a291-cc1a-40a8-bea0-eaeaff92bffd','d181bdd6-5862-4615-adac-bdd636a368e6',82,'text','Mục tiêu: cho bệnh nhân thấy sự nghiêm túc trong điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0886ca48-d47d-4b5c-8b58-4efba747f204','d181bdd6-5862-4615-adac-bdd636a368e6',83,'text','Ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7108f865-1538-47d0-bc78-b46c2d0a2242','d181bdd6-5862-4615-adac-bdd636a368e6',84,'text','- Bác sĩ phân tích phim X-quang như thế nào?- Quy trình hội chẩn trước khi cấy implant- Cách kiểm tra khớp cắn sau phục hình- Vì sao bác sĩ cần lập kế hoạch trước khi niềng?- Một buổi chuẩn bị điều trị diễn ra như thế nào?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8f021813-0419-496f-bd5b-e953b04f92b4','d181bdd6-5862-4615-adac-bdd636a368e6',85,'text','Nội dung này giúp nâng tầm hình ảnh bác sĩ từ “người làm dịch vụ” thành **chuyên gia có quy trình**.',NULL,NULL,NULL,NULL,NULL);
