INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4349526-04bf-468a-80ce-c398868001d1','85211885-3902-4e01-84c8-278cfe35cf7f',87,'text','*Ví dụ:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('75d23ddc-851f-4103-acae-53ae14b617dd','85211885-3902-4e01-84c8-278cfe35cf7f',88,'text','- *Không phải răng nào cũng nên bọc sứ*- *Điều trị nha khoa tốt không chỉ là đẹp, mà còn phải bền*- *Bác sĩ giỏi không chỉ làm nhanh, mà phải làm đúng*- *Nha khoa tử tế là tư vấn đúng nhu cầu, không ép điều trị*- *Một nụ cười đẹp phải phù hợp với gương mặt, tuổi tác và tính cách*',NULL,NULL,NULL,NULL,NULL);
