INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d45fa7c-d44b-4f74-b0d3-0cbc9bf69e02','22d40274-0e0f-42c4-93fe-7b8181d2596e',93,'text','Trong nha khoa, thương hiệu cá nhân phải dựa trên **niềm tin và trách nhiệm chuyên môn**, không nên chỉ chạy theo viral.',NULL,NULL,NULL,NULL,NULL);
