INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1858761a-1ac3-410e-bde8-75a60604a073','22d40274-0e0f-42c4-93fe-7b8181d2596e',95,'text','- Hứa hẹn quá mức- So sánh công kích đối thủ- Dùng hình ảnh điều trị gây hiểu lầm- Chỉ nói về giá rẻ- Tạo nội dung giật gân làm mất tính chuyên nghiệp',NULL,NULL,NULL,NULL,NULL);
